final:
module RefModule(
    input clk,
    input reset_n,
    output reg [4:0] lfsr_out
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
        if (!reset_n)
            lfsr_out <= 5'b00001;
        else
            lfsr_out <= {lfsr_out[3:0], lfsr_out[4] ^ lfsr_out[2]};
    end
endmodule
